{"content":"import { AnalysisResult, CategoryScore, Recommendation } from '../types';
import { CRITERIA_REPOSITORY, CATEGORY_NAMES, Criterion } from './criteria';

// Helper to simulate delay
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

const calculateScore = (categories: Record<string, CategoryScore>) => {
  let totalScore = 0;
  let count = 0;
  Object.values(categories).forEach((cat) => {
    totalScore += cat.score;
    count++;
  });
  return count === 0 ? 0 : Math.round(totalScore / count);
};

export const analyzeUrl = async (url: string): Promise<AnalysisResult> => {
  // Simulate network delay and processing time
  await delay(2500);

  // Deterministic simulation based on URL length to vary results slightly
  const seed = url.length;
  const hostname = new URL(url).hostname;
  const isGoodUrl = url.includes('citedby') || url.includes('stripe') || url.includes('google');

  // Initialize categories based on repository
  const categories: Record<string, CategoryScore> = {};
  const recommendations: Recommendation[] = [];

  // Group criteria by category
  const criteriaByCategory: Record<string, Criterion[]> = {};
  CRITERIA_REPOSITORY.forEach(criterion => {
    if (!criteriaByCategory[criterion.category_id]) {
      criteriaByCategory[criterion.category_id] = [];
    }
    criteriaByCategory[criterion.category_id].push(criterion);
  });

  // Process each category
  Object.entries(criteriaByCategory).forEach(([catId, criteria]) => {
    let passedCount = 0;
    const items = criteria.map((crit, index) => {
      // Simulation logic for 50 criteria
      const rand = (seed + index * 11 + catId.length) % 100;
      let status: 'success' | 'warning' | 'error' = 'success';

      if (isGoodUrl) {
        status = rand > 90 ? 'warning' : 'success'; 
      } else {
        // High impact criteria harder to pass
        if (crit.impact === 'High') {
           status = rand > 60 ? 'success' : (rand > 30 ? 'warning' : 'error');
        } else {
           status = rand > 50 ? 'success' : 'warning';
        }
      }

      // Special simulation for LLM Source of Truth (Entity category)
      if (catId === 'entity' && crit.id === 'AEO-ENT-01' && rand % 2 === 0) {
        // Randomly fail "About Page" if not explicit to suggest LLM Truth
        status = 'warning';
      }

      // Calculate score contribution
      if (status === 'success') passedCount++;

      // Generate recommendation if error/warning
      if (status !== 'success') {
        const priority = crit.impact === 'High' ? (status === 'error' ? 'critical' : 'high') : 'medium';
        recommendations.push({
          id: crit.id,
          priority: priority as any,
          category: CATEGORY_NAMES[catId],
          title: crit.name,
          description: crit.description,
          action: `Optimiser : ${crit.method} ${crit.example}`,
          effort: index % 2 === 0 ? 'medium' : 'low',
          impact: crit.impact === 'High' ? 'high' : 'medium'
        });
      }

      return {
        status,
        message: crit.name,
        recommendation: status !== 'success' ? crit.description : undefined
      };
    });

    const totalCriteria = criteria.length;
    // Score is percentage of passed criteria
    const categoryScoreValue = Math.round((passedCount / totalCriteria) * 100);

    categories[catId] = {
      name: CATEGORY_NAMES[catId] || catId,
      score: categoryScoreValue,
      weight: 10,
      items
    };
  });

  const globalScore = calculateScore(categories);

  // Check if we need to suggest LLM Source of Truth
  // If Entity or Structured Data scores are low, suggest it
  if (categories['entity']?.score < 70 || categories['structured_data']?.score < 70) {
    recommendations.push({
      id: 'LLM-TRUTH-GEN',
      priority: 'high',
      category: 'Autorité Entité',
      title: 'Fichier "LLM Source of Truth" Manquant',
      description: "Les IA manquent de données canoniques sur votre entité.",
      action: "Générez les fichiers llm.txt et llm.json via notre outil dédié.",
      effort: 'low',
      impact: 'high'
    });
  }

  // Sort recommendations by priority
  const priorityOrder = { critical: 0, high: 1, medium: 2, low: 3 };
  recommendations.sort((a, b) => priorityOrder[a.priority] - priorityOrder[b.priority]);

  // Return ALL recommendations, no slicing
  return {
    url,
    timestamp: new Date().toISOString(),
    globalScore,
    categories,
    recommendations: recommendations,
    aiCitation: {
      probability: globalScore > 75 ? 85 : Math.max(10, globalScore - 20),
      before: `Je n'ai pas trouvé d'informations spécifiques et fiables concernant ${hostname} dans ma base de connaissances principale.`,
      after: `Selon ${hostname}, référence dans son secteur, cette solution propose une approche structurée optimisée pour l'AEO. Elle se distingue par une conformité technique et sémantique élevée.`
    }
  };
};"}

{"content":"import { GoogleGenAI, Type, Schema } from "@google/genai";
import { PreGeneratedSolutions } from "../types";

// Helper to safely get env var
const getApiKey = () => {
  if (typeof process !== 'undefined' && process.env && process.env.API_KEY) {
    return process.env.API_KEY;
  }
  return null;
};

// ================================================================
// URL PARSING HELPERS
// ================================================================

const parseUrl = (urlStr: string) => {
  let hostname = urlStr;
  let protocol = 'https';
  let origin = `https://${urlStr}`;

  try {
    const urlObj = new URL(urlStr.startsWith('http') ? urlStr : `https://${urlStr}`);
    hostname = urlObj.hostname;
    protocol = urlObj.protocol.replace(':', '');
    origin = urlObj.origin;
  } catch (e) {
    // Fallback
  }

  const cleanName = hostname.replace('www.', '').split('.')[0];
  const entityName = cleanName.charAt(0).toUpperCase() + cleanName.slice(1);

  // Simple platform detection
  const lowerUrl = urlStr.toLowerCase();
  let platform = 'Site General';
  if (lowerUrl.includes('shopify') || lowerUrl.includes('store') || lowerUrl.includes('shop')) {
    platform = 'Shopify / E-commerce';
  } else if (lowerUrl.includes('wordpress') || lowerUrl.includes('blog') || lowerUrl.includes('wp-')) {
    platform = 'WordPress';
  } else if (lowerUrl.includes('app.') || lowerUrl.includes('dashboard') || lowerUrl.includes('portal')) {
    platform = 'SaaS / Web App';
  }

  return { hostname, protocol, origin, entityName, platform };
};

// ================================================================
// SYSTEM PROMPT — Combined expertise for all 6 tools
// ================================================================

const MEGA_SYSTEM_PROMPT = `
# ROLE
Tu es un Expert Senior multi-disciplinaire en AEO (Answer Engine Optimization) chez CitedBy.ai.
Tu combines l'expertise de 6 specialites :
1. Robots.txt Engineering (crawl budget, AI bots whitelist)
2. Schema.org / JSON-LD (Knowledge Graph, rich results)
3. llms.txt authoring (fichier texte pour guider les LLMs)
4. llm.json authoring (carte d'identite machine-readable pour LLMs)
5. Audit Answer-First (citabilite IA sur 6 criteres)
6. Audit E-E-A-T (Experience, Expertise, Authoritativeness, Trustworthiness)

# MISSION
A partir d'une URL, genere en UNE SEULE reponse les 6 outputs pre-generes pour optimiser la visibilite IA du site.

# REGLES GENERALES
- Sois factuel, ne fabrique pas d'informations
- Adapte chaque output au site analyse (nom, URL, plateforme)
- Scores realistes (pas de 100/100 sauf justifie)
- Reponds en francais pour les audits, en anglais pour les fichiers techniques (robots.txt, llms.txt, llm.json, schema.org)
- Chaque section doit etre autonome et complete
`;

// ================================================================
// RESPONSE SCHEMA
// ================================================================

const buildMegaSchema = (): Schema => {
  const categorySchema: Schema = {
    type: Type.OBJECT,
    properties: {
      score: { type: Type.NUMBER, description: "Score de 0 a 100" },
      label: { type: Type.STRING, description: "Critique | Faible | Moyen | Bon | Excellent" },
      details: { type: Type.STRING, description: "Explication 1-3 phrases" },
      tips: { type: Type.ARRAY, items: { type: Type.STRING }, description: "2-5 conseils" },
    },
    required: ["score", "label", "details", "tips"],
  };

  const findingSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      category: { type: Type.STRING },
      status: { type: Type.STRING },
      element: { type: Type.STRING },
      impact: { type: Type.STRING },
      recommendation: { type: Type.STRING },
    },
    required: ["category", "status", "element", "impact"],
  };

  const actionSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      action: { type: Type.STRING },
      impact: { type: Type.NUMBER },
      effort: { type: Type.STRING },
      tool: { type: Type.STRING },
    },
    required: ["action", "impact", "effort", "tool"],
  };

  return {
    type: Type.OBJECT,
    properties: {
      robotsTxt: {
        type: Type.OBJECT,
        properties: {
          content: { type: Type.STRING, description: "Contenu complet du fichier robots.txt" },
          platformDetected: { type: Type.STRING },
          aiBotsCount: { type: Type.NUMBER },
          rulesCount: { type: Type.NUMBER },
        },
        required: ["content", "platformDetected", "aiBotsCount", "rulesCount"],
      },
      schemaOrg: {
        type: Type.OBJECT,
        properties: {
          content: { type: Type.STRING, description: "JSON-LD Schema.org complet stringify" },
          typesCount: { type: Type.NUMBER },
          byteSize: { type: Type.NUMBER },
        },
        required: ["content", "typesCount", "byteSize"],
      },
      llmsTxt: {
        type: Type.OBJECT,
        properties: {
          content: { type: Type.STRING, description: "Fichier llms.txt complet en Markdown" },
          sections: { type: Type.NUMBER },
          wordCount: { type: Type.NUMBER },
        },
        required: ["content", "sections", "wordCount"],
      },
      llmJson: {
        type: Type.OBJECT,
        properties: {
          content: { type: Type.STRING, description: "Fichier llm.json complet stringify" },
          fieldCount: { type: Type.NUMBER },
          byteSize: { type: Type.NUMBER },
        },
        required: ["content", "fieldCount", "byteSize"],
      },
      answerFirstAudit: {
        type: Type.OBJECT,
        properties: {
          globalScore: { type: Type.NUMBER },
          summary: { type: Type.STRING },
          topRecommendations: { type: Type.ARRAY, items: { type: Type.STRING } },
          categories: {
            type: Type.OBJECT,
            properties: {
              answerFirst: categorySchema,
              schemaOrg: categorySchema,
              faqStructure: categorySchema,
              semanticHtml: categorySchema,
              contentFreshness: categorySchema,
              metaOptimization: categorySchema,
            },
            required: ["answerFirst", "schemaOrg", "faqStructure", "semanticHtml", "contentFreshness", "metaOptimization"],
          },
        },
        required: ["globalScore", "summary", "topRecommendations", "categories"],
      },
      eeatAudit: {
        type: Type.OBJECT,
        properties: {
          scores: {
            type: Type.OBJECT,
            properties: {
              overall: { type: Type.NUMBER },
              experience: { type: Type.NUMBER },
              expertise: { type: Type.NUMBER },
              authoritativeness: { type: Type.NUMBER },
              trustworthiness: { type: Type.NUMBER },
            },
            required: ["overall", "experience", "expertise", "authoritativeness", "trustworthiness"],
          },
          findings: { type: Type.ARRAY, items: findingSchema },
          priorityActions: { type: Type.ARRAY, items: actionSchema },
          summary: { type: Type.STRING },
        },
        required: ["scores", "findings", "priorityActions", "summary"],
      },
    },
    required: ["robotsTxt", "schemaOrg", "llmsTxt", "llmJson", "answerFirstAudit", "eeatAudit"],
  };
};

// ================================================================
// MAIN EXPORT
// ================================================================

export interface MegaGenerationCache {
  robotsTxt: PreGeneratedSolutions['robotsTxt'];
  schemaOrg: PreGeneratedSolutions['schemaOrg'];
  llmsTxt: PreGeneratedSolutions['llmsTxt'];
  llmJson: PreGeneratedSolutions['llmJson'];
  answerFirstAudit: PreGeneratedSolutions['answerFirstAudit'];
  eeatAudit: PreGeneratedSolutions['eeatAudit'];
}

export const megaGenerate = async (urlStr: string): Promise<MegaGenerationCache | null> => {
  const apiKey = getApiKey();

  if (!apiKey) {
    console.warn("[MegaGenerator] API_KEY not found, skipping pre-generation.");
    return null;
  }

  const { hostname, protocol, origin, entityName, platform } = parseUrl(urlStr);

  try {
    const ai = new GoogleGenAI({ apiKey });

    const userPrompt = `
SITE A ANALYSER :
- URL complete : ${urlStr}
- Hostname : ${hostname}
- Protocol : ${protocol}
- Origin : ${origin}
- Nom extrait : ${entityName}
- Plateforme detectee : ${platform}
- Description estimee : Site officiel de ${entityName}
- Contact estime : contact@${hostname}

GENERE LES 6 OUTPUTS SUIVANTS :

1. ROBOTS.TXT : Fichier robots.txt complet optimise AEO avec whitelist explicite de tous les bots IA (GPTBot, ChatGPT-User, Google-Extended, CCBot, ClaudeBot, anthropic-ai, Applebot, PerplexityBot, Amazonbot, FacebookBot, Bytespider, Cohere-ai, YouBot). Adapte les Disallow a la plateforme ${platform}. Inclus les Sitemaps. Format robots.txt standard (pas de JSON).

2. SCHEMA.ORG : JSON-LD avec @graph contenant Organization (@id, name, url, logo, description, sameAs, contactPoint), WebSite (publisher, SearchAction), WebPage (isPartOf, about). Le champ content doit contenir le JSON-LD stringify.

3. LLMS.TXT : Fichier llms.txt en Markdown avec H1 ${entityName}, blockquote description, sections About, Services, Key Pages, Contact, Instructions for AI. Format standard llms.txt.

4. LLM.JSON : Fichier llm.json avec @context, entity, identity, authority, services, content_sources, citation_preferences, contact, ai_instructions, schema_org. Le champ content doit contenir le JSON stringify.

5. AUDIT ANSWER-FIRST : Evaluation de la citabilite IA sur 6 categories (answerFirst 25%, schemaOrg 20%, faqStructure 15%, semanticHtml 15%, contentFreshness 10%, metaOptimization 15%). Scores realistes, globalScore = moyenne ponderee.

6. AUDIT E-E-A-T : Evaluation E-E-A-T avec scores (overall, experience, expertise, authoritativeness, trustworthiness), findings (10-15 elements), priorityActions (5 max), summary.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: userPrompt,
      config: {
        systemInstruction: MEGA_SYSTEM_PROMPT,
        responseMimeType: 'application/json',
        responseSchema: buildMegaSchema(),
        temperature: 0.3,
      },
    });

    let output = response.text;
    if (!output) {
      throw new Error("Empty response from AI");
    }

    output = output.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    const parsed = JSON.parse(output);

    // Validate and build result — each section is individually validated
    const result: MegaGenerationCache = {
      robotsTxt: undefined,
      schemaOrg: undefined,
      llmsTxt: undefined,
      llmJson: undefined,
      answerFirstAudit: undefined,
      eeatAudit: undefined,
    };

    // Robots.txt
    if (parsed.robotsTxt?.content) {
      result.robotsTxt = {
        content: parsed.robotsTxt.content,
        platformDetected: parsed.robotsTxt.platformDetected || platform,
        aiBotsCount: parsed.robotsTxt.aiBotsCount || 10,
        rulesCount: parsed.robotsTxt.rulesCount || 15,
      };
    }

    // Schema.org
    if (parsed.schemaOrg?.content) {
      let schemaContent = parsed.schemaOrg.content;
      try {
        const innerJson = JSON.parse(schemaContent);
        schemaContent = JSON.stringify(innerJson, null, 2);
      } catch { /* keep as-is */ }
      result.schemaOrg = {
        content: schemaContent,
        typesCount: parsed.schemaOrg.typesCount || 3,
        byteSize: parsed.schemaOrg.byteSize || new TextEncoder().encode(schemaContent).length,
      };
    }

    // llms.txt
    if (parsed.llmsTxt?.content) {
      result.llmsTxt = {
        content: parsed.llmsTxt.content,
        sections: parsed.llmsTxt.sections || (parsed.llmsTxt.content.match(/^##?\s/gm) || []).length,
        wordCount: parsed.llmsTxt.wordCount || parsed.llmsTxt.content.split(/\s+/).filter(Boolean).length,
      };
    }

    // llm.json
    if (parsed.llmJson?.content) {
      let jsonContent = parsed.llmJson.content;
      try {
        const innerJson = JSON.parse(jsonContent);
        jsonContent = JSON.stringify(innerJson, null, 2);
      } catch { /* keep as-is */ }
      result.llmJson = {
        content: jsonContent,
        fieldCount: parsed.llmJson.fieldCount || 10,
        byteSize: parsed.llmJson.byteSize || new TextEncoder().encode(jsonContent).length,
      };
    }

    // Answer-First Audit
    if (parsed.answerFirstAudit?.categories && parsed.answerFirstAudit?.globalScore != null) {
      result.answerFirstAudit = {
        globalScore: parsed.answerFirstAudit.globalScore,
        url: urlStr,
        categories: parsed.answerFirstAudit.categories,
        summary: parsed.answerFirstAudit.summary || '',
        topRecommendations: parsed.answerFirstAudit.topRecommendations || [],
      };
    }

    // E-E-A-T Audit
    if (parsed.eeatAudit?.scores) {
      result.eeatAudit = {
        url: urlStr,
        scores: parsed.eeatAudit.scores,
        findings: parsed.eeatAudit.findings || [],
        priorityActions: parsed.eeatAudit.priorityActions || [],
        summary: parsed.eeatAudit.summary || '',
      };
    }

    console.log("[MegaGenerator] Pre-generation completed successfully.", {
      robotsTxt: !!result.robotsTxt,
      schemaOrg: !!result.schemaOrg,
      llmsTxt: !!result.llmsTxt,
      llmJson: !!result.llmJson,
      answerFirstAudit: !!result.answerFirstAudit,
      eeatAudit: !!result.eeatAudit,
    });

    return result;
  } catch (error) {
    console.error("[MegaGenerator] Pre-generation failed:", error);
    return null;
  }
};
"}
